  size = 'md', 
  error = false, 
  disabled = false, 
  placeholder = '',
  value,
  onChange,
  onFocus,
  onBlur,
  ariaDescribedBy,
  id,
  type = 'text',
  name,
}) => {
  // Calcul des classes en fonction de la taille
  const sizeClasses = {
    sm: 'px-[var(--spacing-sm)] py-[var(--spacing-xs)] text-[var(--font-size-sm)] min-h-[32px]',
    md: 'px-[var(--spacing-sm)] py-[var(--spacing-sm)] text-[var(--font-size-md)] min-h-[40px]',
    lg: 'px-[var(--spacing-md)] py-[var(--spacing-sm)] text-[var(--font-size-lg)] min-h-[48px]',
  };

  // Calcul des classes de bordure selon l'état
  const borderColorClass = disabled
    ? 'border-[var(--color-border-disabled)]'
    : error
    ? 'border-[var(--color-danger-500)]'
    : 'border-[var(--color-border-default)] hover:border-[var(--color-border-strong)] focus:border-[var(--color-border-focus)]';

  // Calcul des classes de fond et texte
  const bgClass = disabled 
    ? 'bg-[var(--color-bg-disabled)]' 
    : 'bg-[var(--color-bg-primary)]';

  const textColorClass = disabled
    ? 'text-[var(--color-text-disabled)]'
    : 'text-[var(--color-text-primary)]';

  const placeholderColorClass = 'placeholder-[var(--color-text-tertiary)]';

  return (
    <input
      id={id}
      type={type}
      name={name}
      value={value}
      onChange={onChange}
