```jsx
const Card = ({ 
  children, 
  padding = 'md', 
  className = '',
  role = 'article',
  ariaLabel = null
}) => {
  // Mapping des niveaux de padding aux variables CSS
  const paddingMap = {
    sm: 'var(--component-card-padding-sm)',
    md: 'var(--component-card-padding-md)',
    lg: 'var(--component-card-padding-lg)'
  };

  const paddingValue = paddingMap[padding] || paddingMap.md;

  return (
    <div
      role={role}
      aria-label={ariaLabel}
      style={{
        padding: paddingValue,
        backgroundColor: 'var(--component-card-bg)',
        borderColor: 'var(--component-card-border)',
        boxShadow: 'var(--component-card-shadow)'
      }}
      className={`
        rounded-[var(--component-card-radius)]
        border
        border-solid
        transition-shadow
        duration-200
        hover:shadow-lg
        focus-within:outline
        focus-within:outline-2
        focus-within:outline-offset-2
        focus-within:outline-blue-500
        ${className}
      `}
    >
      {children}
    </div>
  );
};

